package main

import (
    "crypto/tls"
    "fmt"
    "net/http"
)

// Compliant: Using HTTPS with proper TLS configuration
func sendSensitiveDataSecurely() {
    // GOOD: Using HTTPS for encrypted communication
    client := &http.Client{
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion: tls.VersionTLS12,
            },
        },
    }
    resp, err := client.Get("https://api.example.com/sensitive-data")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer resp.Body.Close()
}

package main

import (
    "golang.org/x/crypto/ssh"
    "net"
)

// Compliant: Using SFTP over SSH
func connectSecurely() {
    // GOOD: Using SSH for encrypted file transfer
    config := &ssh.ClientConfig{
        User: "username",
        Auth: []ssh.AuthMethod{
            ssh.Password("password"),
        },
        HostKeyCallback: ssh.InsecureIgnoreHostKey(), // Use proper verification in production
    }

    conn, err := ssh.Dial("tcp", "example.com:22", config)
    if err != nil {
        return
    }
    defer conn.Close()
}
